/**
 * Mock plugin PluginA
 * Registers processors for Scan, DI, and Init stages.
 */

module.exports = {
  processors: {
    Scan: [
      ctx => {
        ctx.log?.push?.('PluginA: Scan stage executed');
        if (!ctx.metadata.pluginA) ctx.metadata.pluginA = {};
        ctx.metadata.pluginA.scanned = true;
      }
    ],
    DI: [
      ctx => {
        ctx.log?.push?.('PluginA: DI stage executed');
        ctx.container.pluginAService = { name: 'PluginAService' };
      }
    ],
    Init: [
      ctx => {
        ctx.log?.push?.('PluginA: Init stage executed');
        ctx.container.pluginAService.initialized = true;
      }
    ]
  }
};